{
  "summary": "The paper proposes mining noisy parallel code translation datasets from large monolingual corpora using document similarity methods, especially Word Movers Distance, to enable supervised code translation without manual dataset curation. Experiments demonstrate that models trained on these noisy datasets achieve competitive performance and robustness to noise across multiple language pairs, including less-studied ones.",
  "strengths": [
    {
      "point": "Novel approach to create parallel datasets from non-parallel corpora",
      "evidence": "The paper uses document similarity metrics to mine noisy parallel pairs, bypassing the need for expensive manual curation."
    },
    {
      "point": "Demonstrated robustness of models to noise in mined datasets",
      "evidence": "Models trained on noisy pairs perform comparably to those trained on ground truth, with only moderate degradation at up to 30% noise."
    },
    {
      "point": "Comprehensive evaluation across multiple language pairs and large datasets",
      "evidence": "Experiments include CodeNet with 10 language pairs, showing practical utility beyond popular languages."
    },
    {
      "point": "Identification of Word Movers Distance as an effective similarity metric",
      "evidence": "WMD outperforms other similarity methods like TF-IDF and Okapi-BM25 in matching code documents."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent unsupervised or weakly supervised code translation methods",
      "evidence": "No baselines using back-translation or pre-training on monolingual code are cited or compared."
    },
    {
      "point": "Insufficient justification and analysis of similarity threshold selection",
      "evidence": "No ablation or principled method to choose thresholds; sensitivity and generalizability are unclear."
    },
    {
      "point": "Missing details on preprocessing, tokenization, and hyperparameters for similarity methods",
      "evidence": "Critical implementation details for TF-IDF, BM25, LDA, LSI, and WMD are omitted, hindering reproducibility."
    },
    {
      "point": "Evaluation metrics rely heavily on BLEU and CodeBLEU, which may not fully capture semantic equivalence",
      "evidence": "Limited use of computational accuracy @k and no human evaluation or deeper semantic analyses."
    },
    {
      "point": "No statistical significance testing reported",
      "evidence": "Results lack confidence intervals or tests, making robustness of improvements uncertain."
    },
    {
      "point": "Ambiguity in definition of 'document' and no analysis of document length or complexity effects",
      "evidence": "Unclear whether documents are files, functions, or snippets; no study on how this impacts similarity or dataset quality."
    },
    {
      "point": "No discussion on scalability and computational cost of WMD on large corpora",
      "evidence": "WMD is computationally expensive but runtime or feasibility on CodeNet scale is not addressed."
    },
    {
      "point": "Limited generalizability beyond pairwise language translation",
      "evidence": "No exploration of multilingual or many-to-many translation scenarios."
    },
    {
      "point": "No evaluation on real-world legacy or industrial codebases",
      "evidence": "Experiments are limited to curated datasets and CodeNet, raising questions about practical applicability."
    },
    {
      "point": "Ethical considerations section is vague and underdeveloped",
      "evidence": "Mentions ethics but lacks concrete analysis of risks, biases, or developer impact."
    },
    {
      "point": "No ablation on different embedding models for WMD",
      "evidence": "Embedding choices for WMD are not explored, which could affect similarity quality."
    },
    {
      "point": "No qualitative analysis of semantic mismatches in noisy pairs",
      "evidence": "Paper does not discuss types of errors introduced by noise or their downstream impact."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed method compare to recent unsupervised or weakly supervised code translation approaches?",
      "motivation": "Understanding relative performance against strong baselines without parallel data is critical to assess novelty and practical value."
    },
    {
      "question": "What is the sensitivity of model performance to the similarity threshold and choice of embedding for WMD?",
      "motivation": "Threshold and embedding choices directly affect dataset quality and reproducibility; ablations would clarify robustness."
    },
    {
      "question": "Can the approach scale computationally to very large corpora given the cost of WMD?",
      "motivation": "Practical feasibility on industrial-scale datasets depends on scalability and runtime considerations."
    },
    {
      "question": "How well does the mined noisy dataset approach generalize to real-world legacy codebases with diverse styles and domains?",
      "motivation": "Applicability beyond curated datasets is important for real-world adoption."
    },
    {
      "question": "Would human evaluation or more semantic-aware metrics confirm the quality of mined pairs and translation outputs?",
      "motivation": "Automated metrics may not fully capture semantic correctness; human judgments could validate claims."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
